function severity_label($s) {
    return [ 'mild' => 'Лёгкая', 'moderate' => 'Средняя', 'severe' => 'Тяжёлая' ][$s] ?? $s;
}
function status_label($s) {
    return [ 'scheduled' => 'Запланирован', 'completed' => 'Завершён', 'cancelled' => 'Отменён',
            'new' => 'Новая', 'approved' => 'Одобрена', 'rejected' => 'Отклонена' ][$s] ?? $s;
}
